import base64, io
parts = [
"",
"",
"",
"",
"",
"",
"",
"",
"",
"",
"",
]
parts[7] = (
""
""
""
)
b64 = "".join(parts)
h = 0
for ch in b64:
    h = ((h * 31) + ord(ch)) & 0xffffffff
print("len", len(b64), "hash", format(h, "x"), "expect len 9488 hash 26ea3754")
raw = base64.b64decode(b64)
open("avatar.jpg", "wb").write(raw)
from PIL import Image
im = Image.open(io.BytesIO(raw))
print("image", im.format, im.size, im.mode)
